pub(crate) const PURE_PROFILE_SKIP_PREFIXES: &[&str] = &[
    "process_",
    "socket",
    "db_",
    "ws_",
    "file_",
    "stream_",
    "path_exists",
    "path_listdir",
    "path_mkdir",
    "path_unlink",
    "path_rmdir",
    "path_chmod",
    "open_builtin",
    "async_sleep",
    "future_",
    "promise_",
    "thread_",
    "lock_",
    "rlock_",
    "chan_",
    "asyncio_",
    "asyncgen_",
    "anext_",
    "io_wait",
    "spawn",
    "block_on",
    "cancel_token_",
    "cancelled",
    "cancel_current",
    "sleep_register",
    "contextlib_async",
    "time_",
    "deflate_raw",
    "inflate_raw",
    "bz2_",
    "gzip_",
    "lzma_",
    "zlib_",
    "compression_",
    "msgpack_",
    "cbor_",
    "hash_new",
    "hash_update",
    "hash_digest",
    "hash_hexdigest",
    "hash_copy",
    "hmac_",
    "pbkdf2_",
    "scrypt",
    "compare_digest",
    "secrets_",
    "ast_",
    "zipfile_",
    "glob_",
    "tempfile_",
    "tarfile_",
];

#[inline]
pub(crate) fn pure_profile_skips_import(name: &str) -> bool {
    PURE_PROFILE_SKIP_PREFIXES
        .iter()
        .any(|prefix| name.starts_with(prefix))
}
